questions.question:
Choose the best answer.
Which of the following statements shows object initialization correctly?
A) int a = 10;
B) float b == 10;
C) String s;
D) String s = India;

questions.answer:
public class StudentInfo {
    public static void main(String[] args) {
        String name = "Ani";
        int age = 13;
        String studentClass = "8";
        char section = 'C';
        System.out.println(name + " " + age + " " + studentClass + section);
    }
}

public class PatternPrint {
    public static void main(String[] args) {
        System.out.println("* * *");
        System.out.println("* $ *");
    }
}

public class Calculator {
    public static void main(String[] args) {
        int a = 20;
        int b = 5;
        System.out.println("Sum = " + (a + b));
        System.out.println("Difference = " + (a - b));
        System.out.println("Product = " + (a * b));
        System.out.println("Quotient = " + (a / b));
    }
}

public class GroceryBill {
    public static void main(String[] args) {
        double rice = 2 * 45;
        double sugar = 1.5 * 40;
        double milk = 3 * 30;
        double total = rice + sugar + milk;
        double finalAmount = total - 20;
        System.out.println("Final amount = " + finalAmount);
    }
}

public class ScooterSales {
    public static void main(String[] args) {
        int price = 134000;
        int quantity = 25;
        int amount = price * quantity;
        System.out.println("Amount received = " + amount);
    }
}

public class AverageOfFive {
    public static void main(String[] args) {
        int a = 12;
        int b = 18;
        int c = 24;
        int d = 30;
        int e = 16;
        double average = (a + b + c + d + e) / 5.0;
        System.out.println("Average = " + average);
    }
}
